#include <stdio.h>
#include <stdlib.h>

int compare(const void *a, const void *b){
    return (*(int*)a) - (*(int*)b);
}

int main(){
    int T;
    if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N, Q;
        scanf("%d %d", &N, &Q);
        int *arr = (int*)malloc(N * sizeof(int));
        for(int i=0;i<N;i++) scanf("%d", &arr[i]);
        while(Q--){
            int x;
            scanf("%d", &x);
            int *p = (int*)bsearch(&x, arr, N, sizeof(int), compare);
            if(p) printf("Found
");
            else printf("Not Found
");
        }
        free(arr);
    }
    return 0;
}

