const fs = require('fs');
const data = fs.readFileSync(0, 'utf8').trim().split(/\s+/).map(Number);
let idx = 0;
const T = data[idx++];
let output = [];
for (let t = 0; t < T; t++) {
  const N = data[idx++];
  const Q = data[idx++];
  const arr = data.slice(idx, idx + N);
  idx += N;
  for (let i = 0; i < Q; i++) {
    const x = data[idx++];
    let lo = 0, hi = N - 1, found = false;
    while (lo <= hi) {
      const mid = (lo + hi) >> 1;
      if (arr[mid] === x) { found = true; break; }
      else if (arr[mid] < x) lo = mid + 1;
      else hi = mid - 1;
    }
    output.push(found ? 'Found' : 'Not Found');
  }
}
